+    async fn test_cache_weighs_key_footprint() {
+        // Weighted size charges the key's unique bytes, not just the value.
+        let cache = LanceCache::with_capacity(usize::MAX);
+        let key = "k".repeat(10_000);
+        let value = Arc::new(vec![1_i32]);
